import * as path from 'path';
import * as fs from 'fs';
import * as os from 'os';

// Import chokidar directly from the project's node_modules
const chokidar = await import\('/Users/matthias/Development/claudine/node_modules/chokidar/esm/index.js'\);
console.log\('chokidar exports:', Object.keys\(chokidar\)\);

const projectsPath = path.join\(os.homedir\(\), '.claude/projects'\);
const fullPattern = path.join\(projectsPath, '**/*.jsonl'\);
console.log\('Watching:', fullPattern\);

const watcher = chokidar.watch\(fullPattern, {
  persistent: true,
  ignoreInitial: true,
  depth: 3,
  awaitWriteFinish: { stabilityThreshold: 200 }
}\);

watcher.on\('add', \(p\) => console.log\('ADD:', p\)\);
watcher.on\('change', \(p\) => console.log\('CHANGE:', p\)\);
watcher.on\('unlink', \(p\) => console.log\('UNLINK:', p\)\);
watcher.on\('error', \(e\) => console.log\('ERROR:', e\)\);
watcher.on\('ready', \(\) => console.log\('Watcher ready!'\)\);

// Wait for ready
await new Promise\(resolve => setTimeout\(resolve, 2000\)\);

// Touch a file
const dirs = fs.readdirSync\(projectsPath, { withFileTypes: true }\).filter\(d => d.isDirectory\(\)\);
let testFile = null;
for \(const dir of dirs\) {
  const files = fs.readdirSync\(path.join\(projectsPath, dir.name\)\).filter\(f => f.endsWith\('.jsonl'\)\);
  if \(files.length > 0\) {
    testFile = path.join\(projectsPath, dir.name, files[0]\);
    break;
  }
}

console.log\('Appending to:', testFile\);
fs.appendFileSync\(testFile, '\\n'\);

await new Promise\(resolve => setTimeout\(resolve, 2000\)\);
console.log\('Done waiting. Closing.'\);
await watcher.close\(\);
